import{_ as e,a as d,b as a,c as o}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as r,o as l,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"S3 호환 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/s3.md","filePath":"ko-KR/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ko-KR/upload/s3.md"};function n(p,t,h,u,b,m){return l(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="s3-호환-채널-추가" tabindex="-1">S3 호환 채널 추가 <a class="header-anchor" href="#s3-호환-채널-추가" aria-label="Permalink to &quot;S3 호환 채널 추가&quot;">​</a></h1><p>S3 채널은 S3 API를 지원하는 오브젝트 스토리지를 ImgBed 저장 위치로 사용합니다.</p><p>Cloudflare R2, Backblaze B2, MinIO, AWS S3, 자체 S3 호환 서비스 등에 사용할 수 있습니다.</p><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>오브젝트 스토리지 API 주소</td></tr><tr><td>Bucket 이름</td><td>파일이 저장될 버킷</td></tr><tr><td>Region</td><td>스토리지 리전. Cloudflare R2는 보통 <code>auto</code></td></tr><tr><td>Access Key ID</td><td>S3 접근 키</td></tr><tr><td>Secret Access Key</td><td>S3 비밀 키</td></tr><tr><td>CDN 도메인</td><td>선택 사항. 커스텀 접근 도메인</td></tr></tbody></table><p>Cloudflare R2 S3 API 예시:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://내AccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: R2버킷명</span></span>
<span class="line"><span>Region: auto</span></span></code></pre></div><h2 id="설정-위치" tabindex="-1">설정 위치 <a class="header-anchor" href="#설정-위치" aria-label="Permalink to &quot;설정 위치&quot;">​</a></h2><ol><li>시스템 설정을 엽니다.</li><li>업로드 설정을 엽니다.</li><li><code>채널 추가</code>를 누릅니다.</li><li><code>S3</code>를 선택합니다.</li></ol><h2 id="입력-항목" tabindex="-1">입력 항목 <a class="header-anchor" href="#입력-항목" aria-label="Permalink to &quot;입력 항목&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>채널 이름</td><td>예: <code>R2-S3</code>, <code>MinIO</code></td></tr><tr><td>Endpoint</td><td><code>https://</code>를 포함한 S3 API 주소</td></tr><tr><td>커스텀 CDN 도메인</td><td>선택 사항. 설정하면 링크 생성 시 우선 사용</td></tr><tr><td>Bucket 이름</td><td>저장 대상 버킷</td></tr><tr><td>Region</td><td>R2는 <code>auto</code>, 그 외는 서비스 문서에 맞게 입력</td></tr><tr><td>Access Key ID</td><td>S3 접근 키</td></tr><tr><td>Secret Access Key</td><td>S3 비밀 키</td></tr><tr><td>Path-style access</td><td>MinIO 등 일부 호환 서비스에서 필요할 때만 켬</td></tr><tr><td>용량 제한</td><td>필요할 때만 켬</td></tr></tbody></table><h2 id="r2에서-s3-키-만들기" tabindex="-1">R2에서 S3 키 만들기 <a class="header-anchor" href="#r2에서-s3-키-만들기" aria-label="Permalink to &quot;R2에서 S3 키 만들기&quot;">​</a></h2><p>Cloudflare Dashboard에서 <code>R2 Object Storage</code>를 열고 API Token 관리로 들어갑니다.</p><p>![R2 API Token入口](../../image/upload/s3/r2 api token入口.png)</p><p>대상 버킷에 접근할 수 있는 R2 API Token을 만듭니다.</p><p><img src="`+e+'" alt="API Token 생성" loading="lazy"></p><p>생성된 <code>Access Key ID</code>와 <code>Secret Access Key</code>를 복사합니다.</p><p><img src="'+d+'" alt="Token 값 복사" loading="lazy"></p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><ol><li><code>Endpoint</code>, <code>Bucket</code>, <code>Region</code>을 입력합니다.</li><li>Access Key ID와 Secret Access Key를 입력합니다.</li><li>CDN을 사용한다면 커스텀 CDN 도메인을 입력합니다.</li><li>Path-style access는 필요한 경우에만 켭니다.</li><li>저장합니다.</li></ol><p><img src="'+a+'" alt="S3 설정" loading="lazy"></p><h2 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h2><table tabindex="0"><thead><tr><th>확인 항목</th><th>정상 상태</th></tr></thead><tbody><tr><td>채널 카드</td><td>저장 후 표시됨</td></tr><tr><td>테스트 업로드</td><td>대상 Bucket에 객체 생성</td></tr><tr><td>링크</td><td>ImgBed가 반환한 URL이 열림</td></tr><tr><td>용량 표시</td><td>용량 제한을 쓰는 경우 사용량 표시</td></tr></tbody></table><p><img src="'+o+'" alt="용량 표시" loading="lazy"></p><p>S3 용량 통계는 저장소 API를 실시간으로 전부 스캔하는 방식이 아니라, ImgBed의 D1 파일 기록을 기준으로 다시 계산합니다.</p><h2 id="자주-나는-오류" tabindex="-1">자주 나는 오류 <a class="header-anchor" href="#자주-나는-오류" aria-label="Permalink to &quot;자주 나는 오류&quot;">​</a></h2><ul><li>Endpoint에 <code>https://</code>가 없음.</li><li>Bucket 이름이나 Region이 틀림.</li><li>Access Key에 쓰기 권한이 없음.</li><li>서비스가 Path-style access를 요구함.</li><li>CDN 도메인이 Bucket과 제대로 연결되지 않음.</li></ul>',27)])])}const _=r(c,[["render",n]]);export{k as __pageData,_ as default};
